UPDATE EQ_ROUTE_ORDER SET
    CMD_STATUS = #{cmdStatus}
    ,CMD_STATUS_DESC = #{cmdStatusDesc}

        ,C_EQ_CODE = #{cEqCode}
        ,C_DEVICE_CODE = #{cDeviceCode}


        ,STATUS_CODE = #{statusCode}
        ,STATUS_DESC = #{statusDesc}

    ,UPDATE_DATE = CURRENT_TIMESTAMP

        ,CLOSE_YN = #{closeYn}
        ,CLOSE_DATE = CURRENT_TIMESTAMP

WHERE EQ_CODE = #{eqCode}
AND CMD_ID = #{cmdId}

mapper.select:
SELECT H.*,P.ORDER_NO,P.PLT_NO FROM (SELECT CASE WHEN B.DEVICE_CODE IS NOT NULL THEN 0 ELSE 1 END AS PLACE_POINT, A.* FROM EQ_ROUTE_ORDER A LEFT OUTER JOIN MD_DEVICE_PLACE B ON A.F_EQ_CODE = B.EQ_CODE AND A.F_DEVICE_CODE = B.DEVICE_CODE AND B.MOTION_TYPE = '1' WHERE A.EQ_CODE = #{eqCode} AND CMD_STATUS IN
#{item}
AND CLOSE_YN = 'N') H JOIN DB_ORDER_PALLET_PART_INFO P ON RIGHT(H.BARCODE,4) = P.CASE_NO ORDER BY PLACE_POINT ASC, F_DEVICE_CODE DESC
